import unittest, math, numpy as np

class TestKalmanEngine(unittest.TestCase):
    def test_basic_update(self):
        from modules.kalman_filter_engine import get_kalman_engine
        eng = get_kalman_engine()
        res = eng.filter_price_series([100, 101, 102, 100, 99, 101])
        self.assertIsInstance(res["filtered_prices"], list)

    def test_trend_direction(self):
        from modules.kalman_filter_engine import get_kalman_engine
        eng = get_kalman_engine()
        rising = [100 + i*0.5 for i in range(50)]
        res = eng.filter_price_series(rising)
        self.assertEqual(res["final_trend"], "UP")

class TestOptionsGreeks(unittest.TestCase):
    def test_call_delta_range(self):
        from modules.options_greeks_engine import get_options_greeks_engine
        eng = get_options_greeks_engine()
        res = eng.analyze_option("AAPL", "call", 150, 150, 0.5, 0.04, 0.25)
        self.assertGreater(res["delta"], 0)
        self.assertLess(res["delta"], 1)

    def test_put_call_parity(self):
        from modules.options_greeks_engine import BSMCore, OptionContract
        bsm = BSMCore()
        call = bsm.price(OptionContract("X","call",100,100,1,0.05,0.20))
        put  = bsm.price(OptionContract("X","put", 100,100,1,0.05,0.20))
        # Put-call parity: C - P = S - K*e^(-rT)
        parity = call - put
        expected = 100 - 100 * math.exp(-0.05 * 1)
        self.assertAlmostEqual(parity, expected, places=2)

    def test_gamma_positive(self):
        from modules.options_greeks_engine import get_options_greeks_engine
        eng = get_options_greeks_engine()
        res = eng.analyze_option("TEST","call",100,100,0.5,0.04,0.20)
        self.assertGreater(res["gamma"], 0)

class TestFixedIncome(unittest.TestCase):
    def test_bond_price_positive(self):
        from modules.fixed_income_engine import get_fixed_income_engine
        fi = get_fixed_income_engine()
        res = fi.analyze_bond("US12345", 0.05, 5.0, 980.0)
        self.assertGreater(res["ytm_pct"], 0)

    def test_duration_positive(self):
        from modules.fixed_income_engine import get_fixed_income_engine
        fi = get_fixed_income_engine()
        res = fi.analyze_bond("US99999", 0.04, 10.0, 950.0)
        self.assertGreater(res["modified_duration"], 0)

class TestMacroEngine(unittest.TestCase):
    def test_recession_regime(self):
        from modules.macro_regime_engine import get_macro_regime_engine
        eng = get_macro_regime_engine()
        # Negatif GDP → resesyon
        res = eng.generate_macro_report(-1.0, 3.0, 6.0, 5.0, 47.0, 3.5, 4.0, 30.0)
        self.assertIn("Recession", res["regime"])

    def test_expansion_regime(self):
        from modules.macro_regime_engine import get_macro_regime_engine
        eng = get_macro_regime_engine()
        res = eng.generate_macro_report(4.0, 2.1, 3.5, 4.0, 57.0, 4.0, 3.5, 15.0)
        self.assertIn("Expansion", res["regime"])

